67	__global__ void layernorm_forward_kernel6(floatX* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
68	                                    const floatX*  __restrict__ inp, const floatX*  __restrict__ weight,
69	                                    const floatX* __restrict__ bias, int N, int C) {
70	    assert(blockDim.x == WARP_SIZE);
71	
72	    // load weights and biases into shared memory
73	    // do this before we allow any threads to exit!
74	    extern __shared__ char* params[];
75	    // load128/store128 sometimes generated multiple instructions when the types here were floatX*, so
76	    // let's keep everything as x128
77	    x128* s_weight = reinterpret_cast<x128*>(params);
78	    x128* s_bias = reinterpret_cast<x128*>(params) + (C / x128::size);
79	    x128* s_in = reinterpret_cast<x128*>(params) + ((2 + threadIdx.y) * C / x128::size);
80	
81	    int sidx = (threadIdx.x + WARP_SIZE * threadIdx.y) * x128::size;
82	    for(int i = sidx; i < C; i += blockDim.y * WARP_SIZE * x128::size) {
83	        s_weight[i/x128::size] = load128(weight + i);
84	        s_bias[i/x128::size] = load128(bias + i);
85	    }
86	    __syncthreads();
87	
88	    int idx = blockIdx.x * blockDim.y + threadIdx.y;
89	    if(idx >= N) { return; } // guard
90	
91	    // adjust pointers to current token
92	    inp += idx * C;
93	    out += idx * C;
94	
95	    const float eps = 1e-5f;
96	    float sum = 0.0f;
97	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
98	        const x128 in_data = load128cs(inp + c);
99	        for(int k = 0; k < x128::size; ++k) {
100	            sum += (float)in_data[k];
101	        }
102	        s_in[c / x128::size] = in_data;
103	    }
104	
105	    sum = warpReduceSum(sum);
106	    float m = sum / C;
107	    float v = 0.f;
108	
109	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
110	        const x128 in_data = s_in[c / x128::size];
111	        for(int k = 0; k < x128::size; ++k) {
112	            v += ((float)in_data[k] - m) * ((float)in_data[k] - m);
113	        }
114	    }
115	
116	    v = warpReduceSum(v) / C;
117	    float s = rsqrtf(v + eps);
118	
119	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
120	        const x128 in_data = s_in[c / x128::size];
121	        const x128 w = s_weight[c / x128::size];
122	        const x128 b = s_bias[c / x128::size];
123	        x128 out_data;
124	        for(int k = 0; k < x128::size; ++k) {
125	            float n = s * ((float)in_data[k] - m); // normalized output
126	            float o = n * (float)w[k] + (float)b[k]; // scale and shift it
127	            out_data[k] = (floatX)o;
128	        }
129	
130	        store128cs(out + c, out_data);
131	    }
132	    // cache the mean and rstd for the backward pass later
133	    if(threadIdx.x == 0 && mean != nullptr) {
134	        __stcs(mean + idx, m);
135	    }
136	    // store the rstd, no need to cache it
137	    if(threadIdx.x == 0 && rstd != nullptr) {
138	        __stcs(rstd + idx, s);
139	    }
140	}
