233	__global__ void __launch_bounds__(512, 2) // todo - any warnings on Turing with only 1024 threads?
234	    layernorm_backward_kernel10(floatX* dinp, floatX* dweight, floatX* dbias, float* scratch,
235	                                const floatX* dout, const floatX* inp, const floatX* weight,
236	                                const float* mean, const float* rstd,
237	                                int B, int T, int C) {
238	    int BLOCK_SIZE = blockDim.x;
239	    int warpsInBlock = BLOCK_SIZE / WARP_SIZE; //number of warps in block
240	    extern __shared__ float shared[];
241	
242	    int warpId = threadIdx.x / WARP_SIZE; // warp index within a block
243	    int baseIdx = blockIdx.x * warpsInBlock + warpId;
244	    int warpThreadIdx = threadIdx.x % WARP_SIZE; // Thread index within the warp
245	    int warpsInGrid = gridDim.x * warpsInBlock;
246	    int C_per_iteration = WARP_SIZE * x128::size;
247	    int iterations_C = CEIL_DIV(C, C_per_iteration); // + 2;
248	
249	    // the first half of shared memory is bias, second is weight
250	    size_t rounded_C = CEIL_DIV(C, (32 * x128::size)) * (32 * x128::size);
251	    float* dbias_shared = shared;
252	    float* dweight_shared = shared + rounded_C;
253	    // warp zero doesn't actually write to the _tmp_shared memory locations, so we don't need to reserve memory
254	    // the obvious solution is to change the addressing below to use (threadId.x-32) as offset, but that causes
255	    // register spills, so instead we mess with the base pointer here, which doesn't increase register usage.
256	    float* dbias_tmp_shared = shared + 2 * rounded_C - WARP_SIZE * f128::size;
257	    float* dweight_tmp_shared = shared + 2 * rounded_C + f128::size * BLOCK_SIZE - 2 * WARP_SIZE * f128::size;
258	
259	    // init shared memory to zero
260	    for(int i = threadIdx.x * f128::size; i < rounded_C; i += BLOCK_SIZE * f128::size) {
261	        store128(dbias_shared + i, f128::zeros());
262	        store128(dweight_shared + i, f128::zeros());
263	    }
264	    __syncthreads();
265	
266	    for (int bt = baseIdx; bt < B * T; bt += warpsInGrid) {
267	        const floatX* dout_bt = dout + bt * C;
268	        const floatX* inp_bt = inp +bt * C;
269	        floatX* dinp_bt = dinp + bt * C;
270	
271	        // first: two reduce operations
272	        float dnorm_mean = 0.0f;
273	        float dnorm_norm_mean = 0.0f;
274	        for (int i = warpThreadIdx * x128::size; i < C; i += WARP_SIZE * x128::size) {
275	            x128 dout128_i   = load128(dout_bt + i);
276	            x128 inp128_i    = load128(inp_bt  + i);
277	            x128 weight128_i = load128(weight  + i);
278	            for (int k = 0; k < x128::size; k++) {
279	                float dnorm_i = (float)weight128_i[k] * (float)dout128_i[k];
280	                dnorm_mean += dnorm_i;
281	                dnorm_norm_mean += dnorm_i * (float)inp128_i[k];
282	            }
283	        }
284	
285	        const float mean_bt = mean[bt];
286	        const float rstd_bt = rstd[bt];
287	        dnorm_mean = warpReduceSum(dnorm_mean) / C;
288	        dnorm_norm_mean = warpReduceSum(dnorm_norm_mean) / C * rstd_bt - dnorm_mean * mean_bt * rstd_bt;
289	
290	        for (int c = 0; c < iterations_C; c++) {
291	            int global_index = (warpThreadIdx * x128::size) + (c * C_per_iteration);
292	
293	            x128 dout128   = x128::zeros();
294	            x128 inp128    = x128::zeros();
295	            x128 dinp128   = x128::zeros();
296	            x128 weight128 = x128::zeros();
297	
298	            if(global_index < C) {
299	                dout128 = load128cs(dout_bt + global_index);
300	                inp128 = load128cs(inp_bt + global_index);
301	                dinp128 = load128(dinp_bt + global_index);
302	                weight128 = load128(weight + global_index);
303	            }
304	
305	            for(int o = 0; o < x128::size / f128::size; ++o) {
306	                f128 dbias_f;
307	                f128 dweight_f;
308	                for(int i = 0; i < f128::size; ++i) {
309	                    int x = o * f128::size + i;
310	                    float dout_i = (float)dout128[x];
311	                    float norm_bti = ((float)inp128[x] - mean_bt) * rstd_bt;
312	                    dbias_f[i] = dout_i;
313	                    dweight_f[i] = norm_bti * dout_i;
314	
315	                    float dval = 0.0f;
316	                    dval += (float) weight128[x] * (float)dout128[x]; // term 1
317	                    dval -= dnorm_mean; // term 2
318	                    dval -= norm_bti * dnorm_norm_mean; // term 3
319	                    dval *= rstd_bt; // final scale
320	                    dinp128[x] = (floatX) ((float) dinp128[x] + dval);
321	                }
322	
323	                if (warpId != 0) {
324	                    store128(dbias_tmp_shared + threadIdx.x * f128::size, dbias_f);
325	                    // this seems to generate a 64-bit store, instead of 128-bit.
326	                    // however, forcing 128-bit (e.g., using inline ptx), results in register
327	                    // spilling and much worse performance, so we'll keep it like this for now
328	                    // but ideally, we could reduce the register pressure a little.
329	                    store128(dweight_tmp_shared + threadIdx.x * f128::size, dweight_f);
330	                }
331	                __syncthreads();
332	                if (warpId == 0) {
333	                    for (int j = 1; j < warpsInBlock; j++) {
334	                        f128 dbias_tmp = load128(dbias_tmp_shared + f128::size * (threadIdx.x + j * WARP_SIZE));
335	                        f128 dweight_tmp = load128(dweight_tmp_shared + f128::size * (threadIdx.x + j * WARP_SIZE));
336	                        for(int i = 0; i < f128::size; ++i) {
337	                            dbias_f[i] += dbias_tmp[i];
338	                            dweight_f[i] += dweight_tmp[i];
339	                        }
340	                    }
341	                }
342	                __syncthreads();
343	                if (warpId == 0) {
344	                    f128 db_old = load128(dbias_shared + global_index + f128::size * o);
345	                    f128 dw_old = load128(dweight_shared + global_index + f128::size * o);
346	                    for(int i = 0; i < f128::size; ++i) {
347	                        dbias_f[i] += db_old[i];
348	                        dweight_f[i] += dw_old[i];
349	                    }
350	                    store128(dbias_shared + global_index + f128::size * o, dbias_f);
351	                    store128(dweight_shared + global_index + f128::size * o, dweight_f);
352	                }
353	            }
354	            if(global_index < C) {
355	                // cache in L2 as this is read by the next kernel, but bypass L1 to minimise thrashing
356	                store128cg(dinp_bt + global_index, dinp128);
357	            }
358	        }
359	    }
360	    __syncthreads();
361	    // Each block writes its partial sum to global memory
362	    // The last block to finish becomes responsible for summing up all the partial sums
363	    // This is done by atomically incrementing a flag (cleared to 0 before launching the kernel)
364	    unsigned int* scratchFlag = (unsigned int*)(scratch);
365	    // Increment scratch pointer by a full cacheline so that everything remains cacheline aligned
366	    scratch += 32;
367	    float* scratch_dbias = scratch;
368	    float* scratch_dweight = scratch + C;
369	    for(int i = threadIdx.x * f128::size; i < C; i += BLOCK_SIZE * f128::size) {
370	        // Write to global memory in the same "shared memory banking friendly" order
371	        store128(scratch_dbias + i + 2*C*blockIdx.x, load128(dbias_shared + i));
372	        store128(scratch_dweight + i + 2*C*blockIdx.x, load128(dweight_shared + i));
373	    }
374	    __syncthreads();
375	    // that portion of shared memory is no longer used, so we can repurpose it for the scratch flag.
376	    unsigned int *tmp_flag = (unsigned int*)(shared + 2*rounded_C);
377	    if (threadIdx.x == 0) {
378	        *tmp_flag = atomicInc(scratchFlag, gridDim.x);
379	    }
380	    __syncthreads();
381	    if (*tmp_flag == gridDim.x-1) {
382	        // Reduction of the partial sums by the final block
383	        // todo - there isn't enough parallelism even inside that single SM...
384	        // ==> so could maybe split into another kernel with YET ANOTHER level of reduction?!
385	        for(int i = threadIdx.x * f128::size; i < C; i += BLOCK_SIZE * f128::size) {
386	            f128 dbias_accum = f128::zeros();
387	            f128 dweight_accum = f128::zeros();
388	
389	            for (int read_block_idx = 0; read_block_idx < gridDim.x; read_block_idx++) {
390	                int offset = i + 2*C*read_block_idx;
391	                f128 dbias128 = load128(scratch_dbias + offset);
392	                f128 dweight128 = load128(scratch_dweight + offset);
393	                for(int k = 0; k < f128::size; k++) {
394	                    dbias_accum[k] += dbias128[k];
395	                    dweight_accum[k] += dweight128[k];
396	                }
397	            }
398	            store128(dbias_shared + i, dbias_accum);
399	            store128(dweight_shared + i, dweight_accum);
400	        }
401	        __syncthreads();
402	
403	        // convert from float/FP32 to floatX/BF16 for the final write
404	        // this is separate because it cannot use as many warps as the above (f128 vs x128)
405	        // todo - if we split this code into another kernel, we could maybe do it at the same time?
406	        for (int c = warpId; c < iterations_C; c += warpsInBlock) {
407	            int global_index = (warpThreadIdx * x128::size) + (c * C_per_iteration);
408	            if (global_index >= C) {
409	                break;
410	            }
411	
412	            x128 dbias128 = load128(dbias + global_index);
413	            x128 dweight128 = load128(dweight + global_index);
414	            for(int o = 0; o < x128::size / f128::size; ++o) {
415	                f128 s_db = load128(dbias_shared + global_index + o * f128::size);
416	                f128 s_dw = load128(dweight_shared + global_index + o * f128::size);
417	                for(int i = 0; i < f128::size; ++i) {
418	                    int x = o * f128::size + i;
419	                    dbias128[x] = (floatX)(s_db[i] + (float)dbias128[x]);
420	                    dweight128[x] = (floatX)(s_dw[i] + (float)dweight128[x]);
421	                }
422	            }
423	            store128(dbias + global_index, dbias128);
424	            store128(dweight + global_index, dweight128);
425	        }
426	    }
427	}
